{
  "domain_analysis": {
    "business_context": "Evolution of a delivery platform's core domain model from single-recipient to multi-recipient shipments. This is a fundamental change to the Shipment aggregate root — one of the most central entities in any logistics system. The change affects 2 million existing production records and external partner API contracts.",
    "bounded_context": "Shipment Management / Order Fulfillment — the core bounded context that governs how packages move from sender to recipient(s). This change ripples into adjacent contexts: Routing, Notifications, Billing, and Partner Integration.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods being transported from an origin to one or more destinations. The aggregate root that owns the relationship to Recipients." },
      { "term": "Recipient", "definition": "A party designated to receive delivery of goods within a Shipment. Identified by name, address, phone number, and now also delivery preferences." },
      { "term": "Delivery Preferences", "definition": "Recipient-specific instructions governing how and when delivery should occur (e.g., time windows, signature requirements, safe-place instructions, authority-to-leave)." },
      { "term": "Primary Recipient", "definition": "PROPOSED — in a multi-recipient shipment, the recipient designated as the default or authoritative contact. Existence and semantics are currently ambiguous in the spec." },
      { "term": "Shipment Status", "definition": "The lifecycle state of a Shipment. In a multi-recipient model, status semantics become complex: is a Shipment 'delivered' when the first recipient receives, or the last?" },
      { "term": "Split Shipment", "definition": "A Shipment whose goods are physically divided to reach multiple recipients at different addresses. Distinct from a multi-drop route where one vehicle visits multiple stops." },
      { "term": "Multi-Drop Route", "definition": "A single delivery run visiting multiple recipient addresses in sequence. The physical fulfillment model for multi-recipient shipments." },
      { "term": "Partner API", "definition": "External system interface through which partner organizations consume shipment data. Currently contracts around a single-recipient model." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment must have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A shipment without a recipient has no destination and cannot be routed, delivered, or billed. This is a physical constraint of the logistics domain — goods must go somewhere.",
      "testable_assertion": "Creating or updating a Shipment with zero Recipients must be rejected by the domain model."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient within a Shipment must have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum fields required for delivery execution and failed-delivery contact. Without them, a courier cannot complete delivery or reach the recipient.",
      "testable_assertion": "Adding a Recipient with a null or empty name, address, or phone number must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a Shipment must have delivery preferences, defaulting to standard preferences if none are specified.",
      "invariant": false,
      "invariant_justification": "Delivery preferences are a business policy enhancement. The system must function with sensible defaults — a VP could change what 'standard' means.",
      "testable_assertion": "A Recipient added without explicit delivery preferences must be assigned the platform's default delivery preferences."
    },
    {
      "id": "BR-4",
      "rule": "Recipient ordering within a Shipment must be deterministic and preserved.",
      "invariant": true,
      "invariant_justification": "Route optimization, delivery sequencing, and billing allocation depend on a stable, ordered list of recipients. Non-deterministic ordering would corrupt routing and make delivery sequence unpredictable.",
      "testable_assertion": "Retrieving a Shipment's Recipients must always return them in the same order they were added or explicitly reordered."
    },
    {
      "id": "BR-5",
      "rule": "Existing single-recipient shipments must remain valid and fully functional without any data migration that alters their business meaning.",
      "invariant": true,
      "invariant_justification": "2 million shipments in production represent completed, in-progress, and auditable delivery records. Corrupting their meaning would break billing reconciliation, compliance records, and customer trust.",
      "testable_assertion": "All existing shipments with one recipient must be queryable, displayable, and operable identically to their pre-migration behavior."
    },
    {
      "id": "BR-6",
      "rule": "Shipment status must reflect the aggregate delivery state across all Recipients.",
      "invariant": true,
      "invariant_justification": "A Shipment's status is the source of truth for customer communication, billing triggers, and SLA measurement. If status does not accurately reflect the state of all recipients, the system is lying to stakeholders.",
      "testable_assertion": "A Shipment with 3 Recipients where 2 are delivered and 1 is pending must NOT report status as 'Delivered'."
    },
    {
      "id": "BR-7",
      "rule": "External partner APIs must continue to receive valid shipment data during and after the transition, even if they only support single-recipient format.",
      "invariant": true,
      "invariant_justification": "Breaking partner API contracts causes immediate operational failures in integrated systems — missed scans, lost tracking, billing disputes. This is a system integrity constraint.",
      "testable_assertion": "Partner API payloads for multi-recipient shipments must either flatten to the primary recipient or use a versioned endpoint; they must never send malformed or empty recipient data."
    },
    {
      "id": "BR-8",
      "rule": "Billing for a multi-recipient Shipment must account for each recipient's delivery cost independently.",
      "invariant": false,
      "invariant_justification": "Billing strategy (per-recipient, per-shipment, blended) is a business policy decision that leadership may change. The invariant is that billing must be calculable, not how it is calculated.",
      "testable_assertion": "A multi-recipient Shipment must produce a billing breakdown that attributes cost to each recipient delivery."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The creator specifies multiple Recipients with different addresses and delivery preferences",
      "then": "The Shipment is created with all Recipients preserved in order, each with their own delivery preferences"
    },
    {
      "id": "AC-2",
      "given": "An existing single-recipient Shipment created before the model change",
      "when": "The Shipment is loaded from the database",
      "then": "It is represented as a Shipment with a one-element Recipient list, fully backward-compatible with all existing operations"
    },
    {
      "id": "AC-3",
      "given": "A multi-recipient Shipment where some Recipients have been delivered and others have not",
      "when": "The Shipment status is queried",
      "then": "The status reflects a partial-delivery state (e.g., 'Partially Delivered') and each Recipient has an individual delivery status"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment is synced to an external partner API that only supports single-recipient format",
      "when": "The API payload is constructed",
      "then": "The system applies a documented flattening strategy (e.g., primary recipient) and logs a warning that additional recipients were not transmitted"
    },
    {
      "id": "AC-5",
      "given": "A Shipment with multiple Recipients",
      "when": "One Recipient is removed",
      "then": "The Shipment retains at least one Recipient; attempting to remove the last Recipient is rejected with a domain error"
    },
    {
      "id": "AC-6",
      "given": "A Shipment with multiple Recipients",
      "when": "A notification event fires (e.g., 'out for delivery')",
      "then": "Each Recipient receives a notification tailored to their delivery preferences and specific delivery window"
    },
    {
      "id": "AC-7",
      "given": "The database migration is applied to production",
      "when": "All 2 million existing shipments are queried",
      "then": "Zero shipments have null or empty Recipient lists, and all original recipient data is intact and unchanged"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A multi-recipient Shipment where two Recipients share the same address but have different delivery preferences",
      "expected_behavior": "Both Recipients are preserved as distinct entries. Route optimization may consolidate the physical stop, but each Recipient's preferences (e.g., one requires signature, one does not) must be honored independently."
    },
    {
      "scenario": "A Recipient is added to a Shipment that is already in-transit",
      "expected_behavior": "The domain must define whether mid-transit recipient addition is permitted. If allowed, the route must be recalculated and the new Recipient's status starts at 'Pending'. If disallowed, the operation must be rejected with a clear domain error referencing the Shipment's lifecycle state."
    },
    {
      "scenario": "All Recipients except one cancel their delivery on a multi-recipient Shipment",
      "expected_behavior": "The Shipment degrades gracefully to a single-recipient shipment. Cancelled recipients are soft-deleted or marked with a 'Cancelled' status — not removed — to preserve audit trail. The Shipment itself remains active for the remaining Recipient."
    },
    {
      "scenario": "A partner API webhook fires for a multi-recipient Shipment — partner expects exactly one recipient object",
      "expected_behavior": "The integration layer must not break. It should send the primary/first Recipient and include metadata indicating additional recipients exist, or queue a versioned payload if the partner supports it."
    },
    {
      "scenario": "A Shipment has 50+ Recipients (bulk/corporate distribution use case)",
      "expected_behavior": "The system must handle this without performance degradation on status queries, notifications, or route calculation. Pagination or batching may be needed for notification dispatch. The domain should define an upper bound if one exists."
    },
    {
      "scenario": "Two Recipients on the same Shipment have conflicting delivery preferences (e.g., one demands morning-only, another demands evening-only, and the Shipment is a single physical package being split)",
      "expected_behavior": "The system must surface the conflict at creation time or route planning time rather than silently failing at delivery. Conflict resolution strategy must be defined — either reject, require sender resolution, or split into sub-shipments."
    },
    {
      "scenario": "Existing reports, analytics, and dashboards that assume Shipment:Recipient is 1:1",
      "expected_behavior": "Queries using JOINs on shipment-to-recipient will now return multiple rows per shipment. All reporting must be audited for cardinality assumptions or KPIs will silently inflate (e.g., 'shipments delivered' counted per recipient row)."
    }
  ],

  "business_impact": {
    "financial": "High impact. Billing models must evolve to handle per-recipient cost attribution. Revenue opportunity exists in charging for multi-drop convenience. Risk of billing errors during transition if legacy invoicing assumes 1:1 cardinality. Migration and partner API adaptation costs are non-trivial.",
    "operational": "Very high impact. Route optimization algorithms must be rearchitected for multi-stop planning. Courier workflows change — a single shipment may now require multiple delivery attempts, PODs (proof of delivery), and exception handling flows. Dispatch and warehouse operations must understand that one shipment label may map to multiple deliveries.",
    "user": "Moderate positive impact for senders who need multi-recipient distribution (corporate, e-commerce bundles, gift shipments). Potentially confusing for recipients who receive partial shipment notifications. UX must clearly communicate per-recipient status without overwhelming users.",
    "risk": "High. This is a change to the core aggregate root of the logistics domain. Risks include: (1) data migration corruption of 2M records, (2) partner API breakage causing operational outages, (3) reporting/analytics inflation from cardinality change, (4) undefined Shipment lifecycle semantics for partial delivery states, (5) performance degradation if recipient lists grow unbounded.",
    "stakeholders_affected": [
      { "group": "Senders/Shippers", "impact": "Gain multi-recipient capability. Must learn new workflows. Billing becomes more complex." },
      { "group": "Recipients", "impact": "May receive partial-delivery notifications for the first time. Delivery preferences become more granular — net positive if well-communicated." },
      { "group": "Couriers/Drivers", "impact": "Delivery workflow changes significantly. A single shipment scan may now require multiple stops. Training and app updates required." },
      { "group": "External Partners (API consumers)", "impact": "Breaking change risk. Must either version APIs or implement backward-compatible flattening. Partners need advance notice and migration support." },
      { "group": "Finance/Billing team", "impact": "Billing model must be redesigned for per-recipient attribution. Reconciliation logic changes. Audit trail must account for multi-recipient billing disputes." },
      { "group": "Customer Support", "impact": "Must handle new categories of inquiries: partial delivery disputes, per-recipient preference failures, multi-recipient billing questions. Tooling must expose per-recipient status." },
      { "group": "Data/Analytics team", "impact": "All shipment KPIs and reports must be audited for 1:1 cardinality assumptions. Dashboards will break or silently inflate metrics if not updated." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is directionally clear but critically underspecified on several domain-defining questions: Shipment lifecycle semantics for partial delivery, billing model for multi-recipient, whether a 'primary recipient' concept exists, maximum recipient cardinality, and whether mid-transit recipient changes are allowed. These are not implementation details — they are business rules that fundamentally shape the domain model. Without answers, any implementation is guessing at correctness.",
    "high_confidence_areas": [
      "At least one Recipient per Shipment is a hard invariant",
      "Existing 2M shipments must be preserved without semantic change",
      "Partner API backward compatibility is non-negotiable",
      "Per-recipient delivery preferences are the core value proposition",
      "Recipient ordering must be deterministic"
    ],
    "low_confidence_areas": [
      "Shipment status semantics for partial delivery — what states exist and when does a Shipment count as 'Delivered'?",
      "Whether a 'Primary Recipient' concept exists and what authority it carries",
      "Billing model for multi-recipient shipments — per-recipient, per-shipment, or hybrid",
      "Upper bound on recipients per Shipment — unbounded creates performance and UX risks",
      "Whether recipients can be added/removed after Shipment creation, and in which lifecycle states",
      "Physical fulfillment model — is this split-shipment (separate packages) or multi-drop (one vehicle, multiple stops)?"
    ],
    "assumptions": [
      "The 1-to-many relationship is Shipment-to-Recipient, not Shipment-to-Destination (a Recipient is more than just an address)",
      "Delivery preferences are per-Recipient, not per-Shipment — each Recipient can have different preferences",
      "Existing single-recipient shipments are migrated in-place by wrapping the recipient in a collection, not by creating new records",
      "Partner API contracts cannot be unilaterally broken — backward compatibility or versioning is required",
      "The product team intends multi-drop routing, not physically splitting packages into separate shipments"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "Shipment lifecycle semantics for partial delivery are undefined. When a Shipment has 3 Recipients and 2 are delivered, what is the Shipment's status? Is 'Partially Delivered' a new state? When does a Shipment transition to 'Delivered' — first recipient or last? This directly impacts SLA measurement, billing triggers, and customer communication.",
      "affected_stakeholders": ["Senders/Shippers", "Recipients", "Finance/Billing team", "Customer Support"],
      "options": [
        "A: Shipment is 'Delivered' only when ALL recipients have received delivery",
        "B: Shipment is 'Delivered' when ANY recipient receives delivery, with per-recipient sub-statuses",
        "C: Introduce a 'Partially Delivered' state with explicit transition rules"
      ],
      "recommendation": "Option C — 'Partially Delivered' is the most honest representation of reality and gives all stakeholders accurate information. Options A and B both lie about the actual state."
    },
    {
      "type": "ambiguity",
      "description": "No 'Primary Recipient' concept is defined. For partner APIs, billing disputes, notification escalation, and return-to-sender scenarios, the system needs to know which Recipient is authoritative. The spec says 'one or more' but does not distinguish between them.",
      "affected_stakeholders": ["External Partners", "Customer Support", "Finance/Billing team"],
      "options": [
        "A: First Recipient in the ordered list is implicitly primary",
        "B: Explicitly designate one Recipient as 'Primary' with a flag",
        "C: No primary — all Recipients are equal peers"
      ],
      "recommendation": "Option B — an explicit Primary Recipient flag. This is the most operationally sound choice: partner APIs need a single recipient to fall back to, return-to-sender needs a designated address, and billing disputes need a responsible party."
    },
    {
      "type": "ambiguity",
      "description": "Maximum recipient cardinality is unspecified. Without an upper bound, the system could face a 10,000-recipient Shipment that breaks route optimization, notification dispatch, and UI rendering.",
      "affected_stakeholders": ["Couriers/Drivers", "Data/Analytics team", "Senders/Shippers"],
      "options": [
        "A: No hard limit, handle via performance optimization",
        "B: Define a reasonable upper bound (e.g., 20 recipients per Shipment)",
        "C: Tiered limits — standard (5), premium (50), enterprise (custom)"
      ],
      "recommendation": "Option B or C — the domain must define a bound. Even if generous, an explicit limit prevents abuse and gives engineering a performance target."
    },
    {
      "type": "missing_context",
      "description": "The physical fulfillment model is unspecified. Does multi-recipient mean one package split into parts (split-shipment), or one vehicle visiting multiple addresses (multi-drop)? These are fundamentally different logistics operations with different cost structures, routing algorithms, and warehouse processes.",
      "affected_stakeholders": ["Couriers/Drivers", "Senders/Shippers", "Finance/Billing team"],
      "options": [
        "A: Multi-drop — single origin, single vehicle, multiple stops",
        "B: Split-shipment — goods physically divided at warehouse into separate packages",
        "C: Both, determined per-shipment by the sender"
      ],
      "recommendation": "Clarify with product team before implementation. This decision cascades into warehouse operations, routing, billing, and tracking — getting it wrong means rebuilding the core model."
    },
    {
      "type": "missing_context",
      "description": "Recipient mutability rules are undefined. Can recipients be added or removed after Shipment creation? What about after pickup? After partial delivery? Each lifecycle state may have different rules, and getting this wrong creates real-world logistics chaos (e.g., a courier is en route and a recipient is removed).",
      "affected_stakeholders": ["Senders/Shippers", "Couriers/Drivers", "Customer Support"],
      "options": [
        "A: Recipients are immutable after creation — add/remove requires cancelling and recreating the Shipment",
        "B: Recipients can be modified until pickup, then frozen",
        "C: Recipients can be modified at any time with appropriate re-routing"
      ],
      "recommendation": "Option B — mutable until pickup, frozen after. This matches physical logistics reality: once goods leave the warehouse, changing destinations has real operational cost and complexity."
    }
  ],

  "rejection_reasons": []
}

